const now = new Date();
const cutoff = new Date(now.getTime() - 14 * 24 * 60 * 60 * 1000);
const dateFrom = cutoff.toISOString().slice(0, 10);
return [{ json: { dateFrom } }];

const response = $input.first().json;
const contacts = Object.values(response.contacts || {});

// Filter: ai_profiel_data aanwezig + ai_current_situation nog leeg
const toProcess = contacts.filter(c => {
  const fields = c.fields?.all || {};
  return fields.ai_profiel_data && !fields.ai_current_situation;
});

if (toProcess.length === 0) {
  return [];
}

return toProcess.map(c => ({
  json: {
    contactId: c.id,
    naam: `${c.fields?.all?.firstname || ''} ${c.fields?.all?.lastname || ''}`.trim(),
    email: c.fields?.all?.email || '',
    ai_profiel_data: c.fields?.all?.ai_profiel_data,
  }
}));

const item = $input.first().json;
let profiel = {};
try {
  profiel = JSON.parse(item.ai_profiel_data);
} catch (_) {}

// Compact subset voor de LLM — sla grote arrays af op relevante velden
const compact = {
  situatie: profiel.situatie || {},
  recent_interactions: (profiel.recent_interactions || []).slice(0, 5),
  kantoor_intelligence: profiel.kantoor_intelligence || {},
  bekeken_woningen: (profiel.bekeken_woningen || []).slice(0, 5),
  conversatie_stats: profiel.conversatie_stats || {},
  lifestyle: profiel.lifestyle || {},
  financieel: profiel.financieel || {},
  geo_voorkeuren: profiel.geo_voorkeuren || {},
  interesses: profiel.interesses || {},
};

const prompt = `Je ontvangt een AI-profiel JSON van een contactpersoon van makelaardij De Vree. Extraheer de 6 situatievelden op basis van alle beschikbare informatie in het profiel. Als een waarde echt onbekend is, gebruik dan null.

Geef ALLEEN dit JSON object terug, zonder uitleg of markdown:
{
  "huidige_woning": null,
  "motivatie_aankoop": null,
  "budget_indicatie": null,
  "tijdlijn": null,
  "gezinssituatie": null,
  "leefstijl_voorkeur": null
}

Velduitleg:
- huidige_woning: huidige woonsituatie (huurder/eigenaar/inwonend/etc)
- motivatie_aankoop: reden om te kopen of te verkopen
- budget_indicatie: genoemde of impliciete prijsrange of budget
- tijdlijn: wanneer wil het contact kopen/verkopen (bijv. "binnen 3 maanden")
- gezinssituatie: stel/gezin/alleenstaand/etc
- leefstijl_voorkeur: woonwensen en -voorkeuren

PROFIEL:
${JSON.stringify(compact, null, 2)}`;

return [{ json: { contactId: item.contactId, naam: item.naam, prompt } }];

const item = $input.first().json;
const aiOutput = item.text || '';
const contactId = item.contactId;
const naam = item.naam || '';

let cleaned = aiOutput
  .replace(/^```+(json)?\s*/i, '')
  .replace(/\s*```+$/i, '')
  .trim();

let situatie = {};
try {
  situatie = JSON.parse(cleaned);
} catch (_) {
  const m = cleaned.match(/\{[\s\S]*\}/);
  if (m) {
    try { situatie = JSON.parse(m[0]); } catch (_) {}
  }
}

const body = {};
const mapping = [
  ['ai_current_situation',    situatie.huidige_woning],
  ['ai_housing_motivation',   situatie.motivatie_aankoop],
  ['ai_budget_indication',    situatie.budget_indicatie],
  ['ai_timeline',             situatie.tijdlijn],
  ['ai_family_status',        situatie.gezinssituatie],
  ['ai_lifestyle_preference', situatie.leefstijl_voorkeur],
];

for (const [key, val] of mapping) {
  if (val !== null && val !== undefined && val !== '') {
    body[key] = val;
  }
}

if (Object.keys(body).length === 0) {
  return [{ json: { _skip: true, contactId, naam } }];
}

return [{ json: { contactId, naam, body } }];
